 82→/**
 83→ * Format all conversations and folder structure as a prompt for AI organization.
 84→ *
 85→ * Key design: the output JSON should only contain INCREMENTAL changes —
 86→ * new folders + new conversation-to-folder assignments for currently unfiled
 87→ * conversations. Existing folders/conversations must NOT be re-emitted, so
 88→ * a "Merge" import won't touch the user's carefully curated structure.
 89→ */
 90→function formatFolderStructurePrompt(
 91→  sidebarConversations: Array<{ id: string; title: string; url: string }>,
 92→  folderData: { folders: Folder[]; folderContents: Record<string, ConversationReference[]> },
 93→  language: string,
 94→): string {
 95→  const lines: string[] = [];
 96→  const langName = getLanguageName(language);
 97→
 98→  // Build folder lookup
 99→  const foldersById = new Map<string, Folder>();
100→  for (const folder of folderData.folders) {
101→    foldersById.set(folder.id, folder);
102→  }
103→
104→  // Collect IDs of conversations already in folders
105→  const organizedIds = new Set<string>();
106→  for (const [folderId, convs] of Object.entries(folderData.folderContents)) {
107→    if (folderId === ROOT_CONVERSATIONS_ID) continue;
108→    for (const conv of convs) {
109→      organizedIds.add(conv.conversationId);
110→    }
111→  }
112→
113→  // Section 1: Existing folder names (reference only, no conversations listed)
114→  const sortedFolders = [...folderData.folders].sort((a, b) => {
115→    if (a.pinned && !b.pinned) return -1;
116→    if (!a.pinned && b.pinned) return 1;
117→    return (a.sortIndex ?? 0) - (b.sortIndex ?? 0);
118→  });
119→
120→  if (sortedFolders.length > 0) {
121→    lines.push('## Existing Folders (DO NOT re-create or modify)');
122→    lines.push('');
123→    for (const folder of sortedFolders) {
124→      const path = buildFolderPath(folder.id, foldersById);
125→      const convCount = (folderData.folderContents[folder.id] || []).length;
126→      lines.push(`- ${path}  (id: ${folder.id}, ${convCount} conversations)`);
127→    }
128→    lines.push('');
129→  }
130→
131→  // Section 2: Unfiled conversations — these are the ones to organize
132→  const unfiledConvs = sidebarConversations.filter((c) => !organizedIds.has(c.id));
133→  if (unfiledConvs.length > 0) {
134→    lines.push('## Unfiled Conversations (to be organized)');
135→    lines.push('');
136→    for (const conv of unfiledConvs) {
137→      lines.push(`- [${conv.id}] ${conv.title} | ${conv.url}`);
138→    }
139→    lines.push('');
140→  }
141→
142→  // Section 3: Instructions
143→  lines.push('## Instructions');
144→  lines.push('');
145→  lines.push(`Please respond in **${langName}** (folder names, explanations, etc.).`);
146→  lines.push('');
147→  lines.push('Organize the **unfiled conversations** above into folders. Rules:');
148→  lines.push('');
149→  lines.push(
150→    '1. **Do NOT re-output existing folders or their conversations.** The result will be merged (not replaced), so anything you output will be added on top of the current structure.',
151→  );
152→  lines.push(
153→    "2. You MAY place an unfiled conversation into an **existing folder** — just reference that folder's id in `folderContents`.",
154→  );
155→  lines.push(
156→    '3. You MAY create **new folders** as needed. Use a short random hex string (8 chars) as the folder id. Name them in ' +
157→      langName +
158→      '.',
159→  );
160→  lines.push(
161→    "4. New folders can be nested under existing folders by setting `parentId` to the existing folder's id.",
162→  );
163→  lines.push(
164→    '5. Each conversation must keep its original `conversationId` and `url` exactly as shown above.',
165→  );
166→  lines.push(
167→    '6. Only output the **incremental** JSON — new folders + new conversation assignments.',
168→  );
169→  lines.push('');
170→  lines.push('Output format (paste-ready for Gemini Voyager import):');
171→  lines.push('');
172→  lines.push('```json');
173→  lines.push('{');
174→  lines.push('  "format": "gemini-voyager.folders.v1",');
175→  lines.push(`  "exportedAt": "${new Date().toISOString()}",`);
176→  lines.push('  "version": "1.3.3",');
177→  lines.push('  "data": {');
178→  lines.push('    "folders": [');
179→  lines.push('      // ONLY new folders here (omit existing ones)');
180→  lines.push('      {');
181→  lines.push('        "id": "<8-char-hex>",');
182→  lines.push(`        "name": "<folder name in ${langName}>",`);
183→  lines.push('        "parentId": null,');
184→  lines.push('        "isExpanded": true,');
185→  lines.push('        "createdAt": <unix-ms>,');
186→  lines.push('        "updatedAt": <unix-ms>');
187→  lines.push('      }');
188→  lines.push('    ],');
189→  lines.push('    "folderContents": {');
190→  lines.push('      // Can reference EXISTING folder ids or NEW folder ids');
191→  lines.push('      "<folder-id>": [');
192→  lines.push('        {');
193→  lines.push('          "conversationId": "<id from unfiled list>",');
194→  lines.push('          "title": "<title>",');
195→  lines.push('          "url": "<url>",');
196→  lines.push('          "addedAt": <unix-ms>');
197→  lines.push('        }');
198→  lines.push('      ]');
199→  lines.push('    }');
200→  lines.push('  }');
201→  lines.push('}');
202→  lines.push('```');
203→
204→  return lines.join('\n');
205→}
