207→const LEGACY_BASELINE_PX = 1200; // used to migrate old px widths to %
208→const pxFromPercent = (percent: number) => (percent / 100) * LEGACY_BASELINE_PX;
209→
210→const clampNumber = (value: number, min: number, max: number) =>
211→  Math.min(max, Math.max(min, Math.round(value)));
212→
213→const clampPercent = (value: number, min: number, max: number) =>
214→  Math.min(max, Math.max(min, Math.round(value)));
215→
216→const normalizePercent = (
217→  value: number,
218→  fallback: number,
219→  min: number,
220→  max: number,
221→  legacyBaselinePx: number,
222→) => {
223→  if (!Number.isFinite(value)) return fallback;
224→  if (value > max) {
225→    const approx = (value / legacyBaselinePx) * 100;
226→    return clampPercent(approx, min, max);
227→  }
228→  return clampPercent(value, min, max);
229→};
