type ScrollMode = 'jump' | 'flow';

/**
 * Reorderable popup section IDs — order here is the default display order.
 */
const POPUP_SECTION_IDS = [
  'cloudSync',
  'contextSync',
  'timeline',
  'folder',
  'folderSpacing',
  'folderTreeIndent',
  'chatWidth',
  'editInputWidth',
