                </Label>
                <p className="text-muted-foreground mt-1 text-xs">
                  {t('enableMermaidRenderingHint')}
                </p>
              </div>
              <Switch
                id="mermaid-enabled"
                checked={mermaidEnabled}
                onChange={(e) => {
                  setMermaidEnabled(e.target.checked);
                  apply({ mermaidEnabled: e.target.checked });
