  moveDownLabel: string;
}) {
  return (
    <div className="absolute -top-1 right-1 z-10 flex gap-px rounded-md opacity-0 transition-opacity group-hover/reorder:opacity-100">
      <button
        type="button"
        onClick={(e) => {
          e.stopPropagation();
          onMoveUp();
