      // Remove trailing slash
      normalized = normalized.replace(/\/$/, '');

      // Remove www. prefix
      normalized = normalized.replace(/^www\./, '');

      // Basic validation: must contain at least one dot and valid characters
      if (!/^[a-z0-9.-]+\.[a-z]{2,}$/i.test(normalized)) {
        return null;
      }

      return normalized;
    } catch {
      return null;
    }
