          <Card className="border-amber-200 bg-amber-50 p-3 text-amber-900 shadow-sm">
            <div className="flex items-start gap-3">
              <div className="mt-1 text-amber-600">
                <svg
                  width="16"
                  height="16"
                  viewBox="0 0 24 24"
                  fill="currentColor"
