                  setQuoteReplyEnabled(e.target.checked);
                  apply({ quoteReplyEnabled: e.target.checked });
                }}
              />
            </div>
          </CardContent>
        </Card>

        {/* NanoBanana Options - Hidden on Safari due to fetch interceptor limitations */}
        {!isSafariBrowser && (
          <Card className="p-4 transition-all hover:shadow-md">
