                  style={{ left: mode === 'flow' ? '4px' : 'calc(50% + 2px)' }}
                />
                <button
                  className={`relative z-10 rounded-lg px-3 py-2 text-sm font-bold transition-all duration-200 ${
                    mode === 'flow'
