        {/* Cloud Sync */}
        {!isSafariBrowser && wrapSection('cloudSync', <CloudSyncSettings />)}
        {/* Context Sync */}
        {wrapSection('contextSync', <ContextSyncSettings />)}
        {/* Timeline Options */}
        {wrapSection('timeline',
        <Card className="p-4 transition-all hover:shadow-md">
