                  onClick={() => {
                    setMode('flow');
                    apply({ mode: 'flow' });
                  }}
                >
                  {t('flow')}
                </button>
                <button
                  className={`relative z-10 rounded-lg px-3 py-2 text-sm font-bold transition-all duration-200 ${
                    mode === 'jump'
                      ? 'text-primary-foreground'
                      : 'text-muted-foreground hover:text-foreground'
                  }`}
                  onClick={() => {
