      setCustomWebsites(updatedWebsites);
      await setSyncStorage({ gvPromptCustomWebsites: updatedWebsites });
      await revokeCustomWebsitePermission(website);
    },
    [customWebsites, revokeCustomWebsitePermission, setSyncStorage],
  );

