  // Width adjuster for sidebar width (Context-aware: Gemini vs AI Studio)
  const sidebarConfig = useMemo(
    () =>
      isAIStudio
        ? {
            key: 'gvAIStudioSidebarWidth',
            min: AI_STUDIO_SIDEBAR_PX.min,
