                  className="group-hover:text-primary cursor-pointer text-sm font-medium transition-colors"
                >
                  {t('hideOuterContainer')}
                </Label>
                <Switch
                  id="hide-container"
                  checked={hideContainer}
                  onChange={(e) => {
                    setHideContainer(e.target.checked);
                    apply({ hideContainer: e.target.checked });
