  preventAutoScrollEnabled?: boolean;
  forkEnabled?: boolean;
  accountIsolationEnabled?: boolean;
  accountIsolationPlatform?: AccountPlatform;
  aiStudioEnabled?: boolean;
  showMessageTimestamps?: boolean;
}

function SectionReorderControls({
  isFirst,
  isLast,
  onMoveUp,
  onMoveDown,
  moveUpLabel,
  moveDownLabel,
}: {
