              <Switch
                id="input-collapse-enabled"
                checked={inputCollapseEnabled}
                onChange={(e) => {
                  setInputCollapseEnabled(e.target.checked);
                  apply({ inputCollapseEnabled: e.target.checked });
                }}
              />
