              {/* Note about reloading */}
              <div className="bg-primary/5 border-primary/20 mt-3 rounded-md border p-2">
                <p className="text-muted-foreground text-xs">{t('customWebsitesNote')}</p>
              </div>
            </div>
          </CardContent>
        </Card>
        )}

        {/* General Options */}
